#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2026/4/3# @Author : cyq# @File : interfaceLoopModel# @Software: PyCharm# @Desc:from sqlalchemy import Column, INTEGER, JSON, Stringfrom app.model import BaseModelfrom utils import logclass InterfaceLoop(BaseModel):    """    接口 循环    """    __tablename__ = "interface_loop"    loop_type = Column(INTEGER, nullable=True, comment='循环类型')    # for_type 根据次数循环    loop_times = Column(INTEGER, default=1, comment="循环次数 ")    loop_items = Column(JSON, nullable=True, comment="For循环")    loop_item_key = Column(String(12), nullable=True, comment="For循环 KEY")    loop_condition = Column(JSON, nullable=True, comment="根据判断循环")    max_loop =  Column(INTEGER, default=10, comment="最大循环次数 ")    loop_step_num = Column(INTEGER, default=0, comment="子步骤数量")    loop_interval = Column(INTEGER, default=0, comment="间隔时间")    @property    def key(self):        try:            return self.loop_condition.get("key")        except ValueError:            log.error(f"InterfaceLoop {self.loop_condition} has no key")            return None    @property    def value(self):        try:            return self.loop_condition.get("value")        except ValueError:            log.error(f"InterfaceLoop {self.loop_condition} has no value")            return None    @property    def operate(self) -> int:        try:            return self.loop_condition.get("operate")        except ValueError:            log.error(f"InterfaceLoop {self.loop_condition} has no operate")            raise    def __repr__(self):        return f"<InterfaceLoop type ={self.loop_type} />"